"use strict";dotclear.ready(()=>{document.getElementById("edit-entry")?.addEventListener("onetabload",()=>{const e=document.getElementById("series-edit"),t=document.getElementById("id");let s=null,r=null;if(e){const o=t?t.value:0;o||(s=dotclear.htmlToNode('<input type="hidden" name="post_series">')),r=new dotclear.MetaEditor(e,s,"serie",dotclear.getData("editor_series_options")),r.displayMeta("serie",o,"post_meta_serie_input"),dotclear.meta_editor_series=r}const o=document.getElementById("post_meta_serie_input");jQuery(o).autocomplete(r.service_uri,{extraParams:{f:"searchMetadata",metaType:"serie",json:1},delay:1e3,multiple:!0,multipleSeparator:", ",matchSubset:!1,matchContains:!0,parse(e){const t=[];if(e.success)for(const s of e.payload)t[t.length]={data:{id:s.meta_id,count:s.count,percent:s.roundpercent},result:s.meta_id};return t},formatItem:e=>e.id,formatResult:e=>e.result})});const e=document.querySelector("h5 .s-series");if(e){const t=document.querySelectorAll(".s-series:not(label)");t&&dotclear.toggleWithLegend(e,t,{user_pref:"post_series",legend_click:!0})}});
